func (this *ZebpayCore) ParseTrade(trade any, optionalArgs ...any) any {
	//
	// fetchMyTrades
	//
	//     {
	//         "id": "32164924331503616",
	//         "symbol": "LINK_USDT",
	//         "accountType": "SPOT",
	//         "orderId": "32164923987566592",
	//         "side": "SELL",
	//         "type": "MARKET",
	//         "matchRole": "TAKER",
	//         "createTime": 1648635115525,
	//         "price": "11",
	//         "quantity": "0.5",
	//         "amount": "5.5",
	//         "feeCurrency": "USDT",
	//         "feeAmount": "0.007975",
	//         "pageId": "32164924331503616",
	//         "clientOrderId": "myOwnId-321"
	//     }
	//   {
	//     aggregateTradeId: '2659115835',
	//     symbol: 'ETHINR',
	//     price: '292848',
	//     quantity: '0.147',
	//     firstTradeId: '7018766077',
	//     lastTradeId: '7018766081',
	//     tradeTime: '1765381971447',
	//     isBuyerMarketMaker: true
	//   }
	//
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var id any = this.SafeString2(trade, "id", "aggregateTradeId")
	var orderId any = this.SafeString2(trade, "id", "order")
	var timestamp any = this.SafeInteger2(trade, "timestamp", "tradeTime")
	var marketId any = this.SafeString(trade, "symbol")
	market = this.SafeMarket(marketId, market, "_")
	var symbol any = GetValue(market, "symbol")
	var side any = this.SafeStringLower(trade, "side")
	var priceString any = this.SafeString(trade, "price")
	var amountString any = this.SafeString2(trade, "amount", "quantity")
	return this.SafeTrade(map[string]any{
		"id":           id,
		"info":         trade,
		"timestamp":    timestamp,
		"datetime":     this.Iso8601(timestamp),
		"symbol":       symbol,
		"order":        orderId,
		"type":         this.SafeStringLower(trade, "type"),
		"side":         side,
		"takerOrMaker": nil,
		"price":        priceString,
		"amount":       amountString,
		"cost":         this.SafeString(trade, "cost"),
		"fee":          this.SafeDict(trade, "fee"),
	}, market)
}

